#include <iostream>

struct Tracker {
    static int copies;
    static int moves;

    Tracker() = default;

    Tracker(const Tracker&) {
        ++copies;
    }

    Tracker(Tracker&&) noexcept {
        ++moves;
    }
};

int Tracker::copies = 0;
int Tracker::moves  = 0;

int main() {
    int n;
    std::cin >> n;
    Tracker original;
    for (int i = 0; i < n; ++i) {
        char op;
        std::cin >> op;
        if (op == 'C') {
            Tracker t = original;
            (void)t;
        } else {
            Tracker tmp;
            Tracker t = std::move(tmp);
            (void)t;
        }
    }
    std::cout << "Copies: " << Tracker::copies << "\n";
    std::cout << "Moves: " << Tracker::moves << "\n";
    return 0;
}

