#include <iostream>

struct Wallet {
    int* balance;

    Wallet(int b) : balance(new int(b)) {}

    Wallet(Wallet&& other) noexcept : balance(other.balance) {
        other.balance = nullptr;
    }

    ~Wallet() { delete balance; }
};

int main() {
    int b;
    std::cin >> b;
    Wallet a(b);
    Wallet moved = std::move(a);
    std::cout << "Balance: " << *moved.balance << "\n";
    return 0;
}
